"use client";

import { useState, useTransition, useCallback } from "react";
import { useRouter } from "next/navigation";
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  type DragEndEvent,
} from "@dnd-kit/core";
import {
  SortableContext,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable";
import { Plus, ArrowLeft } from "@phosphor-icons/react";
import { Link } from "@/i18n/navigation";
import { ListHeader } from "@/components/ListHeader";
import { ShowRow } from "@/components/ShowRow";
import { AddShowDialog } from "@/components/AddShowDialog";
import { EmptyState } from "@/components/EmptyState";
import {
  updateList,
  addShowToList,
  removeShowFromList,
  updateShowRating,
  reorderListItems,
} from "../actions";

type ListItem = {
  id: string;
  list_id: string;
  show_id: string;
  rating: number | null;
  position: number;
  added_at: string;
  notes: string | null;
  shows: {
    id: string;
    tmdb_id: number;
    imdb_id: string | null;
    title: string;
    poster_path: string | null;
    first_air_date: string | null;
    overview: string | null;
  };
};

type ListDetailClientProps = {
  list: {
    id: string;
    name: string;
    description: string | null;
    is_public: boolean;
    list_items: ListItem[];
  };
  isOwner: boolean;
  existingTmdbIds: number[];
};

export function ListDetailClient({
  list,
  isOwner,
  existingTmdbIds,
}: ListDetailClientProps) {
  const router = useRouter();
  const [isPending, startTransition] = useTransition();
  const [showAddDialog, setShowAddDialog] = useState(false);
  const [items, setItems] = useState(list.list_items);

  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    }),
  );

  const handleDragEnd = useCallback(
    (event: DragEndEvent) => {
      const { active, over } = event;
      if (!over || active.id === over.id) return;

      const oldIndex = items.findIndex((item) => item.id === active.id);
      const newIndex = items.findIndex((item) => item.id === over.id);

      const newItems = [...items];
      const [moved] = newItems.splice(oldIndex, 1);
      newItems.splice(newIndex, 0, moved);

      setItems(newItems);

      startTransition(async () => {
        await reorderListItems(
          list.id,
          newItems.map((item) => item.id),
        );
      });
    },
    [items, list.id, startTransition],
  );

  const handleNameChange = useCallback(
    (name: string) => {
      startTransition(async () => {
        await updateList(list.id, { name });
      });
    },
    [list.id, startTransition],
  );

  const handleDescriptionChange = useCallback(
    (description: string) => {
      startTransition(async () => {
        await updateList(list.id, { description });
      });
    },
    [list.id, startTransition],
  );

  const handleTogglePublic = useCallback(() => {
    startTransition(async () => {
      await updateList(list.id, { is_public: !list.is_public });
      router.refresh();
    });
  }, [list.id, list.is_public, router, startTransition]);

  const handleAddShow = useCallback(
    async (show: {
      tmdb_id: number;
      title: string;
      poster_path: string | null;
      first_air_date: string;
      overview: string;
    }) => {
      startTransition(async () => {
        await addShowToList(list.id, show);
        router.refresh();
      });
    },
    [list.id, router, startTransition],
  );

  const handleRemove = useCallback(
    (itemId: string) => {
      setItems((prev) => prev.filter((item) => item.id !== itemId));
      startTransition(async () => {
        await removeShowFromList(list.id, itemId);
      });
    },
    [list.id, startTransition],
  );

  const handleRatingChange = useCallback(
    (itemId: string, rating: number) => {
      setItems((prev) =>
        prev.map((item) => (item.id === itemId ? { ...item, rating } : item)),
      );
      startTransition(async () => {
        await updateShowRating(list.id, itemId, rating);
      });
    },
    [list.id, startTransition],
  );

  return (
    <div>
      {/* Back link */}
      <Link
        href="/lists"
        className="mb-4 inline-flex items-center gap-1 text-xs text-text-muted transition-colors hover:text-text-secondary"
      >
        <ArrowLeft size={12} />
        Back to lists
      </Link>

      {/* List header */}
      <div className="mb-6">
        <ListHeader
          name={list.name}
          description={list.description}
          isPublic={list.is_public}
          onNameChange={isOwner ? handleNameChange : undefined}
          onDescriptionChange={isOwner ? handleDescriptionChange : undefined}
          onTogglePublic={isOwner ? handleTogglePublic : undefined}
          readOnly={!isOwner}
        />
      </div>

      {/* Add show button */}
      {isOwner && (
        <div className="mb-4">
          <button
            onClick={() => setShowAddDialog(true)}
            className="flex items-center gap-1.5 rounded-[var(--radius-md)] border border-dashed border-border px-3 py-2 text-xs text-text-muted transition-colors hover:border-border-hover hover:text-text-secondary"
          >
            <Plus size={14} />
            Add show
          </button>
        </div>
      )}

      {/* Items list */}
      {items.length === 0 ? (
        <EmptyState
          title="No shows in this list yet"
          description={isOwner ? "Add a show to get started" : undefined}
        />
      ) : (
        <DndContext
          sensors={sensors}
          collisionDetection={closestCenter}
          onDragEnd={handleDragEnd}
        >
          <SortableContext
            items={items.map((i) => i.id)}
            strategy={verticalListSortingStrategy}
          >
            <div className={`space-y-2 ${isPending ? "opacity-70" : ""}`}>
              {items.map((item, index) => (
                <ShowRow
                  key={item.id}
                  id={item.id}
                  title={item.shows.title}
                  posterPath={item.shows.poster_path}
                  rating={item.rating}
                  position={index + 1}
                  onRatingChange={
                    isOwner
                      ? (rating) => handleRatingChange(item.id, rating)
                      : undefined
                  }
                  onRemove={isOwner ? () => handleRemove(item.id) : undefined}
                  readOnly={!isOwner}
                />
              ))}
            </div>
          </SortableContext>
        </DndContext>
      )}

      {/* Add show dialog */}
      <AddShowDialog
        open={showAddDialog}
        onClose={() => setShowAddDialog(false)}
        onAdd={handleAddShow}
        existingTmdbIds={existingTmdbIds}
      />
    </div>
  );
}
