"use client";

import Image from "next/image";
import { getPosterUrl } from "@/lib/tmdb/client";
import {
  DotsSixVertical,
  Star,
  Trash,
  Television,
} from "@phosphor-icons/react";
import { useSortable } from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";
import { RatingBar } from "./ShowCard";

type ShowRowProps = {
  id: string;
  title: string;
  posterPath: string | null;
  rating: number | null;
  position: number;
  onRatingChange?: (rating: number) => void;
  onRemove?: () => void;
  readOnly?: boolean;
};

export function ShowRow({
  id,
  title,
  posterPath,
  rating,
  position,
  onRatingChange,
  onRemove,
  readOnly = false,
}: ShowRowProps) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id, disabled: readOnly });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
  };

  const posterUrl = getPosterUrl(posterPath, "w92");

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={`flex items-center gap-3 rounded-[var(--radius-md)] border border-border bg-bg-surface p-3 transition-colors hover:border-border-hover ${
        isDragging ? "opacity-50 shadow-lg" : ""
      }`}
    >
      {/* Drag handle */}
      {!readOnly && (
        <button
          {...attributes}
          {...listeners}
          className="cursor-grab touch-none text-text-faint hover:text-text-muted active:cursor-grabbing"
          aria-label="Drag to reorder"
        >
          <DotsSixVertical size={20} weight="bold" />
        </button>
      )}

      {/* Position */}
      <span className="w-6 text-center font-mono text-xs font-bold text-text-muted tabular-nums">
        {position}
      </span>

      {/* Poster */}
      <div className="relative h-12 w-8 shrink-0 overflow-hidden rounded-[var(--radius-sm)] bg-bg-elevated">
        {posterUrl ? (
          <Image
            src={posterUrl}
            alt={title}
            fill
            className="object-cover"
            sizes="32px"
          />
        ) : (
          <div className="flex h-full items-center justify-center">
            <Television size={14} className="text-text-faint" />
          </div>
        )}
      </div>

      {/* Title */}
      <span className="flex-1 truncate text-sm font-medium text-text-primary">
        {title}
      </span>

      {/* Rating */}
      <div className="flex items-center gap-2">
        {onRatingChange ? (
          <RatingBar
            value={rating}
            onChange={onRatingChange}
            className="w-24"
          />
        ) : rating ? (
          <span className="flex items-center gap-1 font-mono text-xs text-accent tabular-nums">
            <Star size={12} weight="fill" />
            {rating}
          </span>
        ) : (
          <span className="text-xs text-text-faint">—</span>
        )}
      </div>

      {/* Remove */}
      {onRemove && (
        <button
          onClick={onRemove}
          className="rounded-[var(--radius-sm)] p-1.5 text-text-faint transition-colors hover:bg-error/10 hover:text-error"
          aria-label="Remove from list"
        >
          <Trash size={16} />
        </button>
      )}
    </div>
  );
}
